import { useParams } from "react-router-dom";
import { useEffect, useState } from "react";

function OfferLetterPreview() {
  const { applicationId } = useParams();
  const [offer, setOffer] = useState(null);

  useEffect(() => {
    const offers =
      JSON.parse(localStorage.getItem("offerLetters")) || [];

    setOffer(
      offers.find(
        (o) => String(o.applicationId) === String(applicationId)
      )
    );
  }, [applicationId]);

  if (!offer) return <p>Offer not found.</p>;

  return (
    <div style={{ marginTop: "25px" }}>
      <h2>Offer Letter</h2>

      <p><b>Name:</b> {offer.name}</p>
      <p><b>Email:</b> {offer.email}</p>
      <p><b>Job Title:</b> {offer.jobTitle}</p>

      <hr />

      <p><b>Salary:</b> ₹{offer.salary}</p>
      <p><b>Location:</b> {offer.location}</p>
      <p><b>Joining Date:</b> {offer.joiningDate}</p>
      <p><b>Offer Date:</b> {offer.offerDate}</p>

      {offer.notes && <p><b>Notes:</b> {offer.notes}</p>}
    </div>
  );
}

export default OfferLetterPreview;
